     1→import React, { useState } from 'react';
     2→import { Link, useNavigate } from 'react-router-dom';
     3→import { motion } from 'framer-motion';
     4→import { useAuth } from '../context/AuthContext';
     5→import { useSubscription } from '../context/SubscriptionContext';
     6→import { createCheckoutSession } from '../utils/api';
     7→import { useTranslation } from 'react-i18next';
     8→import './PricingPage.css';
     9→
    10→// Plan metadata — only non-translatable values here
    11→const PLAN_META = [
    12→  { id: 'free',      price: 0,   featureCount: 4, lockedCount: 4, hasBadge: false, highlight: false, priceId: null },
    13→  { id: 'grow',      price: 19,  featureCount: 7, lockedCount: 0, hasBadge: true,  highlight: true,  priceId: process.env.REACT_APP_STRIPE_GROW_PRICE_ID },
    14→  { id: 'scale',     price: 49,  featureCount: 7, lockedCount: 0, hasBadge: true,  highlight: false, priceId: process.env.REACT_APP_STRIPE_SCALE_PRICE_ID },
    15→  { id: 'evolution', price: 99,  featureCount: 8, lockedCount: 0, hasBadge: true,  highlight: false, priceId: process.env.REACT_APP_STRIPE_EVOLUTION_PRICE_ID },
    16→];
    17→
    18→// Comparison table — 4 columns: free, grow, scale, evolution
    19→const COMPARISON_ROWS = [
    20→  { idx: 0,  free: 'trial',    grow: 'unlimited', scale: 'unlimited', evolution: 'unlimited' },
    21→  { idx: 1,  free: '⚠️',      grow: '✅',        scale: '✅',        evolution: '✅' },
    22→  { idx: 2,  free: '❌',       grow: '✅',        scale: '✅',        evolution: '✅' },
    23→  { idx: 3,  free: '❌',       grow: '✅',        scale: '✅',        evolution: '✅' },
    24→  { idx: 4,  free: '❌',       grow: 'partial',   scale: 'partial',   evolution: '✅' },
    25→  { idx: 5,  free: '❌',       grow: '❌',        scale: '✅',        evolution: '✅' },
    26→  { idx: 6,  free: '❌',       grow: '❌',        scale: '✅',        evolution: '✅' },
    27→  { idx: 7,  free: '❌',       grow: '❌',        scale: '✅',        evolution: '✅' },
    28→  { idx: 8,  free: '❌',       grow: '❌',        scale: '❌',        evolution: '✅' },
    29→  { idx: 9,  free: '❌',       grow: '❌',        scale: '❌',        evolution: '✅' },
    30→  { idx: 10, free: 'email',    grow: 'priority',  scale: 'priority',  evolution: 'dedicated' },
    31→  { idx: 11, free: 'addon',    grow: 'addon',     scale: 'addon',     evolution: 'addon' },
    32→];
    33→
    34→const FAQ_COUNT = 6;
    35→
    36→const fadeUp = {
    37→  hidden: { opacity: 0, y: 20 },
    38→  visible: { opacity: 1, y: 0 },
    39→};
    40→
    41→const stagger = {
    42→  hidden: {},
    43→  visible: { transition: { staggerChildren: 0.1 } },
    44→};
    45→
    46→export default function PricingPage() {
    47→  const { currentUser } = useAuth();
    48→  const { subscription } = useSubscription();
    49→  const navigate = useNavigate();
    50→  const { t } = useTranslation();
    51→  const [loadingPlan, setLoadingPlan] = useState(null);
    52→  const [error, setError] = useState('');
    53→
    54→  async function handlePlanSelect(plan) {
    55→    if (plan.id === 'free') {
    56→      navigate('/auth?mode=register');
    57→      return;
    58→    }
    59→
    60→    if (!currentUser) {
    61→      navigate('/auth?mode=register');
    62→      return;
    63→    }
    64→
    65→    if (!plan.priceId || plan.priceId === 'undefined') {
    66→      setError('Payment system is not configured yet. Please add Stripe price IDs to your environment variables.');
    67→      return;
    68→    }
    69→
    70→    setError('');
    71→    setLoadingPlan(plan.id);
    72→    try {
    73→      const { url } = await createCheckoutSession(plan.priceId);
    74→      window.location.href = url;
    75→    } catch (err) {
    76→      setError(err.message || 'Failed to start checkout. Please try again.');
    77→    }
    78→    setLoadingPlan(null);
    79→  }
    80→
    81→  function getPlanCta(plan) {
    82→    if (!currentUser && plan.id !== 'free') return t('pricing.signUpToStart', { defaultValue: 'Sign Up to Start' });
    83→    if (subscription === plan.id) return t('pricing.currentPlan', { defaultValue: '✅ Current Plan' });
    84→    if (plan.id === 'free' && subscription !== 'free') return t('pricing.downgrade', { defaultValue: 'Downgrade' });
    85→    return t(`pricing.plan.${plan.id}.cta`);
    86→  }
    87→
    88→  function translateVal(val) {
    89→    if (val === 'unlimited') return t('pricing.comparison.unlimited', { defaultValue: 'Unlimited' });
    90→    if (val === 'trial')     return t('pricing.comparison.trial',     { defaultValue: '14-day trial' });
    91→    if (val === 'partial')   return t('pricing.comparison.partial',   { defaultValue: '1 tool' });
    92→    if (val === 'email')     return t('pricing.comparison.email',     { defaultValue: 'Email' });
    93→    if (val === 'priority')  return t('pricing.comparison.priority',  { defaultValue: 'Priority' });
    94→    if (val === 'dedicated') return t('pricing.comparison.dedicated', { defaultValue: 'Dedicated' });
    95→    if (val === 'addon')     return t('pricing.comparison.addon',     { defaultValue: '➕ Add-on' });
    96→    return val;
    97→  }
    98→
    99→  return (
   100→    <div className="page">
   101→      <div className="pricing">
   102→        {/* Hero */}
   103→        <motion.div
   104→          className="pricing__hero container"
   105→          initial={{ opacity: 0, y: 30 }}
   106→          animate={{ opacity: 1, y: 0 }}
   107→          transition={{ duration: 0.6 }}
   108→        >
   109→          <span className="badge badge-primary">
   110→            {t('pricing.hero.badge', { defaultValue: 'Simple, Transparent Pricing' })}
   111→          </span>
   112→          <h1 className="pricing__title">
   113→            {t('pricing.hero.titlePre', { defaultValue: 'Choose Your' })}{' '}
   114→            <span className="gradient-text">{t('pricing.hero.titleHighlight', { defaultValue: 'Growth Plan' })}</span>
   115→          </h1>
   116→          <p className="pricing__subtitle">
   117→            {t('pricing.hero.subtitle', { defaultValue: "Start free. Upgrade when you're ready. No contracts, cancel anytime." })}
   118→          </p>
   119→        </motion.div>
   120→
   121→        {error && (
   122→          <div className="container">
   123→            <div className="alert alert-warning" style={{ marginBottom: '2rem' }}>
   124→              ⚠️ {error}
   125→            </div>
   126→          </div>
   127→        )}
   128→
   129→        {/* Plans */}
   130→        <div className="container">
   131→          <motion.div
   132→            className="pricing__plans pricing__plans--4"
   133→            initial="hidden"
   134→            animate="visible"
   135→            variants={stagger}
   136→          >
   137→            {PLAN_META.map((plan) => {
   138→              const features = Array.from({ length: plan.featureCount }, (_, i) =>
   139→                t(`pricing.plan.${plan.id}.feature.${i}`)
   140→              );
   141→              const locked = Array.from({ length: plan.lockedCount }, (_, i) =>
   142→                t(`pricing.plan.${plan.id}.locked.${i}`)
   143→              );
   144→
   145→              return (
   146→                <motion.div
   147→                  key={plan.id}
   148→                  className={`pricing__plan ${plan.highlight ? 'pricing__plan--highlight' : ''} ${subscription === plan.id ? 'pricing__plan--current' : ''}`}
   149→                  variants={fadeUp}
   150→                  whileHover={{ y: plan.highlight ? -8 : -4 }}
   151→                  transition={{ type: 'spring', stiffness: 300, damping: 25 }}
   152→                >
   153→                  {plan.highlight && <div className="pricing__plan-glow" />}
   154→
   155→                  {plan.hasBadge && subscription !== plan.id && (
   156→                    <div className="pricing__plan-badge">
   157→                      {t(`pricing.plan.${plan.id}.badge`)}
   158→                    </div>
   159→                  )}
   160→
   161→                  {subscription === plan.id && (
   162→                    <div className="pricing__plan-badge pricing__plan-badge--current">
   163→                      {t('pricing.currentPlan', { defaultValue: '✅ Current Plan' })}
   164→                    </div>
   165→                  )}
   166→
   167→                  <div className="pricing__plan-header">
   168→                    <h2 className="pricing__plan-name">{t(`pricing.plan.${plan.id}.name`)}</h2>
   169→                    <p className="pricing__plan-desc">{t(`pricing.plan.${plan.id}.desc`)}</p>
   170→                  </div>
   171→
   172→                  <div className="pricing__plan-price">
   173→                    <span className="pricing__plan-amount">€{plan.price}</span>
   174→                    <div className="pricing__plan-period">
   175→                      {plan.price === 0
   176→                        ? t('pricing.forever', { defaultValue: 'forever free' })
   177→                        : t('pricing.month', { defaultValue: '/month' })}
   178→                    </div>
   179→                  </div>
   180→
   181→                  <button
   182→                    className={`btn ${plan.highlight ? 'btn-primary' : 'btn-secondary'} pricing__plan-cta`}
   183→                    onClick={() => handlePlanSelect(plan)}
   184→                    disabled={subscription === plan.id || loadingPlan === plan.id}
   185→                  >
   186→                    {loadingPlan === plan.id ? (
   187→                      <><span className="spinner" /> {t('pricing.processing', { defaultValue: 'Processing...' })}</>
   188→                    ) : (
   189→                      getPlanCta(plan)
   190→                    )}
   191→                  </button>
   192→
   193→                  <div className="pricing__features">
   194→                    {features.map((f) => (
   195→                      <div key={f} className="pricing__feature pricing__feature--included">
   196→                        <span className="pricing__feature-icon">✅</span>
   197→                        <span>{f}</span>
   198→                      </div>
   199→                    ))}
   200→                    {locked.map((f) => (
   201→                      <div key={f} className="pricing__feature pricing__feature--locked">
   202→                        <span className="pricing__feature-icon">🔒</span>
   203→                        <span>{f}</span>
   204→                      </div>
   205→                    ))}
   206→                  </div>
   207→                </motion.div>
   208→              );
   209→            })}
   210→          </motion.div>
   211→        </div>
   212→
   213→        {/* N8n Add-on */}
   214→        <div className="container">
   215→          <motion.div
   216→            className="pricing__addon"
   217→            initial={{ opacity: 0, y: 20 }}
   218→            whileInView={{ opacity: 1, y: 0 }}
   219→            viewport={{ once: true, margin: '-60px' }}
   220→            transition={{ duration: 0.5 }}
   221→          >
   222→            <div className="pricing__addon-left">
   223→              <span className="badge badge-primary pricing__addon-badge">
   224→                {t('pricing.addon.badge', { defaultValue: '⚡ Add-on' })}
   225→              </span>
   226→              <h3 className="pricing__addon-title">
   227→                {t('pricing.addon.title', { defaultValue: 'N8n Automation' })}
   228→              </h3>
   229→              <p className="pricing__addon-desc">
   230→                {t('pricing.addon.desc', { defaultValue: 'Design powerful no-code automations using n8n — available for any plan.' })}
   231→              </p>
   232→              <ul className="pricing__addon-features">
   233→                {[0, 1, 2, 3].map((i) => (
   234→                  <li key={i}>✅ {t(`pricing.addon.feature.${i}`)}</li>
   235→                ))}
   236→              </ul>
   237→            </div>
   238→
   239→            <div className="pricing__addon-right">
   240→              <div className="pricing__addon-price">
   241→                <span className="pricing__addon-amount">
   242→                  {t('pricing.addon.price', { defaultValue: '€10' })}
   243→                </span>
   244→                <span className="pricing__addon-period">
   245→                  {t('pricing.addon.period', { defaultValue: '/ 10 workflows' })}
   246→                </span>
   247→              </div>
   248→              <p className="pricing__addon-renew">
   249→                {t('pricing.addon.renew', { defaultValue: 'No expiry · Works with any plan · Buy more when you need' })}
   250→              </p>
   251→              <button
   252→                className="btn btn-primary pricing__plan-cta"
   253→                onClick={() => {
   254→                  if (!currentUser) navigate('/auth?mode=register');
   255→                }}
   256→              >
   257→                {t('pricing.addon.cta', { defaultValue: 'Get Add-on →' })}
   258→              </button>
   259→            </div>
   260→          </motion.div>
   261→        </div>
   262→
   263→        {/* Comparison table */}
   264→        <div className="container">
   265→          <motion.div
   266→            className="pricing__comparison"
   267→            initial={{ opacity: 0, y: 30 }}
   268→            whileInView={{ opacity: 1, y: 0 }}
   269→            viewport={{ once: true, margin: '-80px' }}
   270→            transition={{ duration: 0.6 }}
   271→          >
   272→            <h2 className="pricing__comparison-title">
   273→              {t('pricing.comparison.title', { defaultValue: 'Full Feature Comparison' })}
   274→            </h2>
   275→            <div className="pricing__table-wrap">
   276→              <table className="pricing__table">
   277→                <thead>
   278→                  <tr>
   279→                    <th>{t('pricing.comparison.featureCol', { defaultValue: 'Feature' })}</th>
   280→                    <th>{t('pricing.plan.free.name', { defaultValue: 'Free' })}</th>
   281→                    <th className="pricing__th--highlight">{t('pricing.plan.grow.name', { defaultValue: 'Grow' })}</th>
   282→                    <th>{t('pricing.plan.scale.name', { defaultValue: 'Scale' })}</th>
   283→                    <th>{t('pricing.plan.evolution.name', { defaultValue: 'Evolution' })}</th>
   284→                  </tr>
   285→                </thead>
   286→                <tbody>
   287→                  {COMPARISON_ROWS.map((row) => (
   288→                    <tr key={row.idx}>
   289→                      <td>{t(`pricing.comparison.row.${row.idx}`)}</td>
   290→                      <td>{translateVal(row.free)}</td>
   291→                      <td className="pricing__td--highlight">{translateVal(row.grow)}</td>
   292→                      <td>{translateVal(row.scale)}</td>
   293→                      <td>{translateVal(row.evolution)}</td>
   294→                    </tr>
   295→                  ))}
   296→                </tbody>
   297→              </table>
   298→            </div>
   299→          </motion.div>
   300→        </div>
   301→
   302→        {/* FAQ */}
   303→        <div className="container pricing__faq">
   304→          <h2 className="pricing__comparison-title">
   305→            {t('pricing.faq.title', { defaultValue: 'Frequently Asked Questions' })}
   306→          </h2>
   307→          <div className="pricing__faq-grid">
   308→            {Array.from({ length: FAQ_COUNT }, (_, i) => (
   309→              <div key={i} className="pricing__faq-item">
   310→                <h4>{t(`pricing.faq.${i}.q`)}</h4>
   311→                <p>{t(`pricing.faq.${i}.a`)}</p>
   312→              </div>
   313→            ))}
   314→          </div>
   315→        </div>
   316→
   317→        {/* CTA */}
   318→        <div className="container pricing__bottom-cta">
   319→          <motion.div
   320→            className="pricing__cta-card"
   321→            initial={{ opacity: 0, y: 20 }}
   322→            whileInView={{ opacity: 1, y: 0 }}
   323→            viewport={{ once: true }}
   324→          >
   325→            <h2>
   326→              {t('pricing.cta.titlePre', { defaultValue: 'Ready to' })}{' '}
   327→              <span className="gradient-text">{t('pricing.cta.titleHighlight', { defaultValue: 'Get Started?' })}</span>
   328→            </h2>
   329→            <p>{t('pricing.cta.subtitle', { defaultValue: 'Join thousands of marketers, founders, and agencies growing with AI.' })}</p>
   330→            <Link to="/auth?mode=register" className="btn btn-primary btn-lg">
   331→              {t('pricing.cta.btn', { defaultValue: 'Start Free Today →' })}
   332→            </Link>
   333→          </motion.div>
   334→        </div>
   335→      </div>
   336→    </div>
   337→  );
   338→}
