     2→import { Link, useSearchParams } from 'react-router-dom';
     3→import { motion } from 'framer-motion';
     4→import { useAuth } from '../context/AuthContext';
     5→import { useSubscription } from '../context/SubscriptionContext';
     6→import { CATEGORIES } from '../data/categories';
     7→import { useTranslation } from 'react-i18next';
     8→import InstagramAuditSection from '../components/InstagramAuditSection';
     9→import './Dashboard.css';
    10→
    11→const stagger = {
    12→  hidden: {},
    13→  visible: { transition: { staggerChildren: 0.08 } },
    14→};
    15→
    16→const fadeUp = {
    17→  hidden: { opacity: 0, y: 20 },
    18→  visible: { opacity: 1, y: 0, transition: { duration: 0.5, ease: [0.22, 1, 0.36, 1] } },
    19→};
    20→
    21→export default function Dashboard() {
    22→  const { currentUser } = useAuth();
    23→  const { subscription, isCategoryLocked, isInTrial, trialDaysRemaining } = useSubscription();
    24→  const [searchParams] = useSearchParams();
    25→  const { t } = useTranslation();
    26→
    27→  const paymentStatus = searchParams.get('payment');
    28→  const inTrial = isInTrial();
    29→  const daysLeft = trialDaysRemaining();
    30→  const trialPct = Math.round((daysLeft / 14) * 100);
    31→
    32→  return (
    33→    <div className="page">
    34→      <div className="container">
    35→        <div className="dashboard">
    36→          {/* Payment success banner */}
    37→          {paymentStatus === 'success' && (
    38→            <motion.div
    39→              className="alert alert-success"
    40→              initial={{ opacity: 0, y: -10 }}
    41→              animate={{ opacity: 1, y: 0 }}
    42→            >
    43→              🎉 {t('dashboard.paymentSuccess', { plan: subscription.charAt(0).toUpperCase() + subscription.slice(1), defaultValue: `Payment successful! Welcome to ${subscription.charAt(0).toUpperCase() + subscription.slice(1)}!` })}
    44→            </motion.div>
    45→          )}
    46→
    47→          {/* Header */}
    48→          <motion.div
    49→            className="dashboard__header"
    50→            initial={{ opacity: 0, y: 20 }}
    51→            animate={{ opacity: 1, y: 0 }}
    52→            transition={{ duration: 0.5 }}
    53→          >
    54→            <div>
    55→              <h1 className="dashboard__greeting">
    56→                {t('dashboard.greeting', { name: currentUser?.displayName?.split(' ')[0] || t('dashboard.guestName', { defaultValue: 'friend' }) })}
    57→              </h1>
    58→              <p className="dashboard__subtitle">{t('dashboard.subtitle')}</p>
    59→            </div>
    60→
    61→            <div className="dashboard__header-right">
    62→              <div className="dashboard__plan-badge">
    63→                <span className={`badge ${subscription === 'free' ? 'badge-free' : 'badge-pro'}`}>
    64→                  {subscription === 'free' && inTrial
    65→                    ? `🎁 ${t('ui.freeTrialBadge', { defaultValue: 'Free Trial' })} · ${t('ui.trialDaysLeft', { count: daysLeft, defaultValue: `${daysLeft} days left` })}`
    66→                    : subscription === 'free'
    67→                    ? t('ui.freePlan', { defaultValue: 'Free Plan' })
    68→                    : subscription === 'grow'
    69→                    ? `⭐ ${t('ui.growPlan', { defaultValue: 'Grow Plan' })}`
    70→                    : subscription === 'scale'
    71→                    ? `💎 ${t('ui.scalePlan', { defaultValue: 'Scale Plan' })}`
    72→                    : subscription === 'evolution'
    73→                    ? `🚀 ${t('ui.evolutionPlan', { defaultValue: 'Evolution Plan' })}`
    74→                    : `✅ ${subscription}`}
    75→                </span>
    76→              </div>
    77→              {(subscription === 'free' || subscription === 'grow') && (
    78→                <Link to="/pricing" className="btn btn-primary btn-sm">
    79→                  {t('ui.upgrade', { defaultValue: 'Upgrade' })} ↗
    80→                </Link>
    81→              )}
    82→            </div>
    83→          </motion.div>
    84→
    85→          {/* Trial countdown (free users in trial) */}
    86→          {subscription === 'free' && inTrial && (
    87→            <motion.div
    88→              className="dashboard__usage"
    89→              initial={{ opacity: 0, y: 16 }}
    90→              animate={{ opacity: 1, y: 0 }}
    91→              transition={{ delay: 0.1 }}
    92→            >
    93→              <div className="dashboard__usage-info">
    94→                <span>🎁 {t('dashboard.trialActive', { defaultValue: 'Free trial — full access active' })}</span>
    95→                <span className="dashboard__usage-count">
    96→                  <strong>{daysLeft}</strong> {t('ui.trialDaysLeft', { count: daysLeft, defaultValue: `${daysLeft} days left` })}
    97→                </span>
    98→              </div>
    99→              <div className="dashboard__usage-bar">
   100→                <div className="dashboard__usage-fill" style={{ width: `${trialPct}%` }} />
   101→              </div>
   102→              <p className="dashboard__usage-note">
   103→                {t('dashboard.trialNote', { defaultValue: 'After your trial, only Keyword Research & Meta Tags remain free. ' })}
   104→                <Link to="/pricing">{t('ui.upgradeForUnlimited', { defaultValue: 'Upgrade for unlimited access' })}</Link>
   105→              </p>
   106→            </motion.div>
   107→          )}
   108→          {/* Post-trial notice for free users */}
   109→          {subscription === 'free' && !inTrial && (
   110→            <motion.div
   111→              className="dashboard__usage"
   112→              initial={{ opacity: 0, y: 16 }}
   113→              animate={{ opacity: 1, y: 0 }}
   114→              transition={{ delay: 0.1 }}
   115→            >
   116→              <p className="dashboard__usage-note" style={{ margin: 0 }}>
   117→                🔒 {t('dashboard.trialEnded', { defaultValue: 'Your free trial has ended. Only Keyword Research & Meta Tags are available. ' })}
   118→                <Link to="/pricing">{t('ui.upgrade', { defaultValue: 'Upgrade' })} →</Link>
   119→              </p>
   120→            </motion.div>
   121→          )}
   122→
   123→          {/* Category Grid */}
   124→          <section className="dashboard__categories">
   125→            <h2 className="dashboard__section-title">
   126→              <span>🚀</span> {t('ui.aiToolCategories', { defaultValue: 'AI Tool Categories' })}
   127→            </h2>
   128→
   129→            <motion.div
   130→              className="dashboard__grid"
   131→              initial="hidden"
   132→              animate="visible"
   133→              variants={stagger}
   134→            >
   135→              {CATEGORIES.map((cat) => {
   136→                const isAddon = !!cat.isAddon && subscription !== 'admin';
   137→                const locked = !isAddon && isCategoryLocked(cat.id);
   138→                const catName = t(`cat.${cat.id}.name`, { defaultValue: cat.name });
   139→                const catDesc = t(`cat.${cat.id}.desc`, { defaultValue: cat.description });
   140→
   141→                return (
